import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { PreferencesService, resetPreferencesIdCounter } from '../../src/services/preferences.service.js';
import { EmailAdapter, InMemoryTransport } from '../../src/adapters/email.adapter.js';
import { SmsAdapter, InMemorySmsTransport } from '../../src/adapters/sms.adapter.js';
import {
  WebhookAdapter,
  InMemoryWebhookTransport,
} from '../../src/adapters/webhook.adapter.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { Database } from '../../src/utils/database.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  NotificationSendEvent,
} from '../../src/events/event-types.js';
import type { User } from '../../src/models/user.js';
import type { EmailTransport, EmailMessage } from '../../src/adapters/email.adapter.js';

/**
 * Integration tests for the full notification pipeline.
 *
 * These tests wire up the complete stack:
 *   EventBus → NotificationService → Adapters (email/sms/webhook)
 *                                   → PreferencesService (preference gating)
 *                                   → NotificationHistoryService (audit logging)
 *
 * Unlike the unit tests which test individual components in isolation,
 * these tests verify that the full pipeline works end-to-end.
 */

function createTestUser(overrides?: Partial<User>): User {
  return {
    id: 'user-1',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

describe('Notification Pipeline Integration', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let historyService: NotificationHistoryService;
  let preferencesService: PreferencesService;

  let emailTransport: InMemoryTransport;
  let emailAdapter: EmailAdapter;
  let smsTransport: InMemorySmsTransport;
  let smsAdapter: SmsAdapter;
  let webhookTransport: InMemoryWebhookTransport;
  let webhookAdapter: WebhookAdapter;

  let userRepository: UserRepository;
  let preferencesRepository: PreferencesRepository;
  let logRepository: NotificationLogRepository;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();

    // Repositories
    userRepository = new UserRepository(db);
    preferencesRepository = new PreferencesRepository(db);
    logRepository = new NotificationLogRepository(db);

    // Adapters with in-memory transports
    emailTransport = new InMemoryTransport();
    emailAdapter = new EmailAdapter({ transport: emailTransport });

    smsTransport = new InMemorySmsTransport();
    smsAdapter = new SmsAdapter({ transport: smsTransport });

    webhookTransport = new InMemoryWebhookTransport();
    webhookAdapter = new WebhookAdapter({
      url: 'https://hooks.example.com/notify',
      transport: webhookTransport,
    });

    // Services — wired together
    notificationService = new NotificationService(eventBus);
    notificationService.registerAdapter(emailAdapter);
    notificationService.registerAdapter(smsAdapter);
    notificationService.registerAdapter(webhookAdapter);

    preferencesService = new PreferencesService(preferencesRepository, userRepository);
    notificationService.setPreferencesService(preferencesService);

    historyService = new NotificationHistoryService(eventBus, logRepository, notificationService);

    // Reset ID counters
    resetNotificationIdCounter();
    resetLogIdCounter();
    resetPreferencesIdCounter();

    // Seed a test user in the repository
    const user = createTestUser();
    userRepository.save(user);
  });

  describe('email channel — end-to-end', () => {
    it('should deliver email notification via order:created event and log to history', async () => {
      const user = createTestUser();

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-100',
          userId: user.id,
          items: [
            { productId: 'p1', name: 'Widget', quantity: 3, unitPrice: 15 },
          ],
          total: 45,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user,
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // 1. Notification was created in NotificationService
      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.channel).toBe('email');
      expect(notifications[0]?.status).toBe('sent');
      expect(notifications[0]?.recipient).toBe('alice@example.com');
      expect(notifications[0]?.type).toBe('order:confirmation');

      // 2. Email was actually sent through the transport
      const emails = emailTransport.getMessages();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('alice@example.com');
      expect(emails[0]?.subject).toContain('Order Confirmation');
      expect(emails[0]?.html).toContain('order-100');

      // 3. History was logged via notification:sent event
      const history = historyService.getHistory();
      expect(history).toHaveLength(1);
      expect(history[0]?.channel).toBe('email');
      expect(history[0]?.status).toBe('sent');
      expect(history[0]?.recipient).toBe('alice@example.com');
      expect(history[0]?.type).toBe('order:confirmation');
    });

    it('should deliver email for order:status-changed event', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-200',
          userId: 'user-1',
          items: [],
          total: 50,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = emailTransport.getMessages();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.subject).toContain('Order Update');

      const history = historyService.getHistory();
      expect(history).toHaveLength(1);
      expect(history[0]?.type).toBe('order:status-update');
    });
  });

  describe('SMS channel — end-to-end', () => {
    it('should deliver SMS notification when sent via notification:send event', async () => {
      const event: NotificationSendEvent = {
        type: 'notification:send',
        payload: {
          type: 'order:confirmation',
          recipient: '+12025551234',
          subject: 'Order Confirmed',
          body: 'Your order has been placed.',
          metadata: { orderId: 'order-300', userId: 'user-1' },
        },
        channels: ['sms'],
        timestamp: new Date(),
      };

      // Enable SMS preferences for this user
      preferencesService.updateSmsPreferences('user-1', {
        enabled: true,
        phoneNumber: '+12025551234',
      });

      await eventBus.emit(event);

      // SMS was sent through the transport
      const smsMessages = smsTransport.getMessages();
      expect(smsMessages).toHaveLength(1);
      expect(smsMessages[0]?.to).toBe('+12025551234');
      expect(smsMessages[0]?.body).toContain('order-300');

      // Notification recorded
      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.channel).toBe('sms');
      expect(notifications[0]?.status).toBe('sent');

      // History logged
      const history = historyService.getHistory();
      expect(history).toHaveLength(1);
      expect(history[0]?.channel).toBe('sms');
    });
  });

  describe('webhook channel — end-to-end', () => {
    it('should deliver webhook notification', async () => {
      const event: NotificationSendEvent = {
        type: 'notification:send',
        payload: {
          type: 'order:confirmation',
          recipient: 'user-1',
          subject: 'Order Confirmed',
          body: 'Your order has been placed.',
          metadata: { orderId: 'order-400', userId: 'user-1' },
        },
        channels: ['webhook'],
        timestamp: new Date(),
      };

      // Enable webhook preferences for this user
      preferencesService.updateWebhookPreferences('user-1', {
        enabled: true,
        url: 'https://hooks.example.com/notify',
      });

      await eventBus.emit(event);

      // Webhook was delivered through the transport
      const deliveries = webhookTransport.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.url).toBe('https://hooks.example.com/notify');
      expect(deliveries[0]?.payload.type).toBe('order:confirmation');
      expect(deliveries[0]?.payload.body).toContain('Your order has been placed.');

      // Notification recorded
      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.channel).toBe('webhook');
      expect(notifications[0]?.status).toBe('sent');

      // History logged
      const history = historyService.getHistory();
      expect(history).toHaveLength(1);
      expect(history[0]?.channel).toBe('webhook');
    });
  });

  describe('multi-channel delivery', () => {
    it('should deliver to multiple channels in a single notification:send event', async () => {
      // Enable SMS and webhook for this user
      preferencesService.updateSmsPreferences('user-1', { enabled: true });
      preferencesService.updateWebhookPreferences('user-1', { enabled: true });

      const event: NotificationSendEvent = {
        type: 'notification:send',
        payload: {
          type: 'user:welcome',
          recipient: 'alice@example.com',
          subject: 'Welcome!',
          body: 'Welcome to TaskFlow Pro.',
          metadata: { userId: 'user-1' },
        },
        channels: ['email', 'sms', 'webhook'],
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // All three channels received the notification
      expect(emailTransport.getMessages()).toHaveLength(1);
      // SMS will fail validation (email is not a valid phone), but adapter won't throw
      // Webhook should succeed
      expect(webhookTransport.getDeliveries()).toHaveLength(1);

      // At least email and webhook notifications recorded
      const notifications = notificationService.getNotifications();
      expect(notifications.length).toBeGreaterThanOrEqual(2);

      // History entries logged for each delivery attempt
      const history = historyService.getHistory();
      expect(history.length).toBeGreaterThanOrEqual(2);
    });
  });

  describe('user preferences — channel gating', () => {
    it('should skip email when email preferences are disabled', async () => {
      // Disable email for user-1
      preferencesService.updateEmailPreferences('user-1', { enabled: false });

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-500',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: createTestUser(),
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // No email should be sent
      expect(emailTransport.getMessages()).toHaveLength(0);
      // No notification recorded (it was skipped)
      expect(notificationService.getNotifications()).toHaveLength(0);
      // No history logged
      expect(historyService.getHistory()).toHaveLength(0);
    });

    it('should skip SMS when SMS preferences are disabled (default)', async () => {
      // SMS is disabled by default — don't enable it
      const event: NotificationSendEvent = {
        type: 'notification:send',
        payload: {
          type: 'order:confirmation',
          recipient: '+12025551234',
          subject: 'Order Confirmed',
          body: 'Your order has been placed.',
          metadata: { orderId: 'order-600', userId: 'user-1' },
        },
        channels: ['sms'],
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // SMS should not be sent — disabled by default
      expect(smsTransport.getMessages()).toHaveLength(0);
      expect(notificationService.getNotifications()).toHaveLength(0);
    });

    it('should skip webhook when webhook preferences are disabled (default)', async () => {
      // Webhook is disabled by default — don't enable it
      const event: NotificationSendEvent = {
        type: 'notification:send',
        payload: {
          type: 'order:confirmation',
          recipient: 'user-1',
          subject: 'Order Confirmed',
          body: 'Your order has been placed.',
          metadata: { orderId: 'order-700', userId: 'user-1' },
        },
        channels: ['webhook'],
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(webhookTransport.getDeliveries()).toHaveLength(0);
      expect(notificationService.getNotifications()).toHaveLength(0);
    });

    it('should respect per-category preferences', async () => {
      // Disable orderConfirmations category for email, keep email enabled
      preferencesService.updateEmailPreferences('user-1', {
        categories: { orderConfirmations: false },
      });

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-800',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: createTestUser(),
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // Order confirmation email should be skipped
      expect(emailTransport.getMessages()).toHaveLength(0);
      expect(notificationService.getNotifications()).toHaveLength(0);
    });

    it('should still allow other categories when one is disabled', async () => {
      // Disable orderConfirmations but keep orderStatusUpdates enabled
      preferencesService.updateEmailPreferences('user-1', {
        categories: { orderConfirmations: false },
      });

      // This is a status update, not a confirmation — should still go through
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-900',
          userId: 'user-1',
          items: [],
          total: 50,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // Status update should still be sent
      expect(emailTransport.getMessages()).toHaveLength(1);
      expect(notificationService.getNotifications()).toHaveLength(1);
    });

    it('should deliver when no preferences exist (email defaults to allowed)', async () => {
      // Create a new user with no preferences
      const user2 = createTestUser({ id: 'user-2', email: 'bob@example.com', name: 'Bob' });
      userRepository.save(user2);
      // Do NOT create preferences for user-2

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1000',
          userId: 'user-2',
          items: [
            { productId: 'p1', name: 'Gadget', quantity: 1, unitPrice: 25 },
          ],
          total: 25,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: user2,
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // Email should be sent — no preferences means email defaults to allowed
      expect(emailTransport.getMessages()).toHaveLength(1);
      expect(emailTransport.getMessages()[0]?.to).toBe('bob@example.com');
    });
  });

  describe('notification history queries', () => {
    it('should log all notifications and support querying by recipient', async () => {
      const user1 = createTestUser();
      const user2 = createTestUser({ id: 'user-2', email: 'bob@example.com', name: 'Bob' });
      userRepository.save(user2);

      // Send to user1
      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-a',
          userId: user1.id,
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: user1,
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      // Send to user2
      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-b',
          userId: user2.id,
          items: [{ productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 20 }],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: user2,
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      // Total history
      expect(historyService.getHistory()).toHaveLength(2);

      // Query by recipient
      expect(historyService.getHistoryByRecipient('alice@example.com')).toHaveLength(1);
      expect(historyService.getHistoryByRecipient('bob@example.com')).toHaveLength(1);

      // Query by type
      expect(historyService.getHistoryByType('order:confirmation')).toHaveLength(2);

      // Query by channel
      expect(historyService.getHistoryByChannel('email')).toHaveLength(2);

      // Query by status
      expect(historyService.getHistoryByStatus('sent')).toHaveLength(2);
    });

    it('should correctly persist history through the log repository', async () => {
      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-persist',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: createTestUser(),
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      // Verify the log is in the repository directly
      const logs = logRepository.findAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]?.notificationId).toBe('notif-0001');
      expect(logs[0]?.recipient).toBe('alice@example.com');
      expect(logs[0]?.channel).toBe('email');
    });
  });

  describe('notification ordering', () => {
    it('should preserve delivery order across concurrent emits through the full pipeline', async () => {
      const deliveryOrder: string[] = [];
      let callCount = 0;

      const orderTrackingTransport: EmailTransport = {
        async sendMail(message: EmailMessage) {
          callCount++;
          // First message is slow, second is fast — tests queue serialization
          const delay = callCount === 1 ? 50 : 5;
          await new Promise((resolve) => setTimeout(resolve, delay));
          deliveryOrder.push(message.subject);
          return { success: true };
        },
      };

      // Build a fresh pipeline with the order-tracking transport
      const freshBus = new EventBus();
      const freshNotifService = new NotificationService(freshBus);
      const trackingEmailAdapter = new EmailAdapter({ transport: orderTrackingTransport });
      freshNotifService.registerAdapter(trackingEmailAdapter);

      const freshLogRepo = new NotificationLogRepository(db);
      const freshHistoryService = new NotificationHistoryService(
        freshBus,
        freshLogRepo,
        freshNotifService,
      );

      const event1: NotificationSendEvent = {
        type: 'notification:send',
        payload: {
          type: 'order:confirmation',
          recipient: 'alice@example.com',
          subject: 'First Notification',
          body: 'First',
          metadata: { orderId: 'order-1' },
        },
        channels: ['email'],
        timestamp: new Date(),
      };

      const event2: NotificationSendEvent = {
        type: 'notification:send',
        payload: {
          type: 'order:status-update',
          recipient: 'alice@example.com',
          subject: 'Second Notification',
          body: 'Second',
          metadata: { orderId: 'order-1', newStatus: 'shipped' },
        },
        channels: ['email'],
        timestamp: new Date(),
      };

      // Emit concurrently
      const p1 = freshBus.emit(event1);
      const p2 = freshBus.emit(event2);
      await Promise.all([p1, p2]);

      // Delivery order must match emit order
      expect(deliveryOrder).toEqual(['First Notification', 'Second Notification']);

      // History should also reflect the correct order
      const history = freshHistoryService.getHistory();
      expect(history).toHaveLength(2);
      expect(history[0]?.subject).toContain('First');
      expect(history[1]?.subject).toContain('Second');
    });
  });

  describe('error handling in the pipeline', () => {
    it('should record failed delivery in history when adapter fails', async () => {
      const failingTransport: EmailTransport = {
        async sendMail() {
          return { success: false, error: 'SMTP server down' };
        },
      };

      const freshBus = new EventBus();
      const freshNotifService = new NotificationService(freshBus);
      const failingEmailAdapter = new EmailAdapter({ transport: failingTransport });
      freshNotifService.registerAdapter(failingEmailAdapter);

      const freshLogRepo = new NotificationLogRepository(db);
      const freshHistoryService = new NotificationHistoryService(
        freshBus,
        freshLogRepo,
        freshNotifService,
      );

      const event: NotificationSendEvent = {
        type: 'notification:send',
        payload: {
          type: 'user:welcome',
          recipient: 'alice@example.com',
          subject: 'Welcome!',
          body: 'Welcome to TaskFlow Pro.',
        },
        channels: ['email'],
        timestamp: new Date(),
      };

      await freshBus.emit(event);

      // Notification should be recorded as failed
      const notifications = freshNotifService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.status).toBe('failed');

      // History should reflect the failure
      const history = freshHistoryService.getHistory();
      expect(history).toHaveLength(1);
      expect(history[0]?.status).toBe('failed');
      expect(history[0]?.error).toBe('SMTP server down');
    });
  });

  describe('event bus audit trail', () => {
    it('should emit notification:sent events that are visible in the event log', async () => {
      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-audit',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: createTestUser(),
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      const eventLog = eventBus.getEventLog();
      const sentEvents = eventLog.filter((e) => e.type === 'notification:sent');
      expect(sentEvents).toHaveLength(1);

      // The full event chain: order:created → notification:sent
      expect(eventLog[0]?.type).toBe('order:created');
      expect(eventLog[1]?.type).toBe('notification:sent');
    });
  });
});

