it('should process order:status-changed event through the full pipeline', async () => {
  const event: OrderStatusChangedEvent = {
    type: 'order:status-changed',
    order: {
      id: 'order-200',
      userId: 'user-1',
      items: [],
      total: 50,
      status: 'shipped',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus: 'confirmed',
    newStatus: 'shipped',
    timestamp: new Date(),
  };

  await eventBus.emit(event);

  // The order:status-changed handler uses order.userId as recipient,
  // which is not a valid email address. The email adapter correctly
  // rejects it, and the notification is recorded as failed.
  const notifications = notificationService.getNotifications();
  expect(notifications).toHaveLength(1);
  expect(notifications[0]?.type).toBe('order:status-update');
  expect(notifications[0]?.subject).toContain('Order Update');
  expect(notifications[0]?.status).toBe('failed');

  // The failure is still logged in history
  const history = historyService.getHistory();
  expect(history).toHaveLength(1);
  expect(history[0]?.type).toBe('order:status-update');
  expect(history[0]?.status).toBe('failed');
});

it('should deliver order status update via notification:send with valid email', async () => {
